var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"숨이 턱까지 차오를 만큼 지치지 않은 채로 잠들면, 종종 나쁜 꿈을 꾼다.","JPN":"息が苦しくなるほど体を酷使していない日は、時々悪い夢を見る。","ENG":"I often have nightmares if I don't exhaust myself to sleep.","TWN":"如果不是累到睡著的話老是會做惡夢。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 식은땀에 절어 깊은 밤 눈을 뜨는 순간이면, 그 꿈이 현실로 이루어지지 않을지 불안을 곱씹는다.","JPN":"そして全身に冷汗をかいて深夜に目を覚まし、その夢が現実になるのではないかという不安に駆られる。","ENG":"Every time I wake up with a start, soaked in a cold sweat, I can't help but wonder if my nightmares will ever come true.","TWN":"全身冒著冷汗在夜裡睜開眼後，又會籠罩在擔心惡夢成真的不安裡。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……나는 대개 상대에게 창을 겨누는 편이었는데, 자네는 매번 내게 역으로 겨누는군.","JPN":"……たいていの場合、私は相手に槍を突きつけるほうだが、君が相手だと毎回逆に突きつけられるな。","ENG":"...Usually, it's I who holds the opponent at spearpoint. With you, I'm always on the other side of the spear.","TWN":"……通常我都是拿劍指著別人的，但每次跟你練習時都是反過來的呢。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"대련은 자네의 승리야. 정확하게 허점을 찔렸어.","JPN":"この手合わせは君の勝ちだ。見事に隙をつかれたよ。","ENG":"You won. Good job delivering a home-thrust.","TWN":"這次的練習是你獲勝，每個動作都命中紅心。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"설령 레드 시프트들이라도, 자네만큼은 단장으로 인정할 걸세.","JPN":"レッドシフトも君のことを団長として認めるだろう。","ENG":"Even the Red Shifts will accept you as their captain, though begrudgingly.","TWN":"就算是紅移也會認同你這位團長吧！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"제 체면을 지켜 주실 요량으로 하는 말씀이라면 괜찮습니다. 버밍엄 교수님.","JPN":"私の面子を立てようとされているのなら大丈夫です、バーミンガム教授。","ENG":"If you're saying that to protect my pride, I'm okay, Professor Birmingham.","TWN":"伯明罕教授，你大可不必說這些話來安慰我。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"지휘에서나 전투에서나, 아직 교수님을 넘어서기엔 갈 길이 멀군요.","JPN":"指揮も戦闘も、まだ教授にはまだまだ敵いません。","ENG":"I still have a long way to go before I outshine you as a leader, or as a fighter.","TWN":"無論是在指揮或是在戰鬥中，我都還差教授一大截呢。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"너무 서두르지 말게. 정진할 목표가 있다는 건 행복한 일이니까.","JPN":"急ぐ必要はない。目標のために精進できるのは幸せなことだ。","ENG":"No need to hurry. Having a goal is a good thing.","TWN":"別太心急，有明確的目標是一件很幸福的事。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"기사단으로 돌아가기 전에 잠시 걷겠나? 새로 만든 산책로가 마음에 들면 좋겠군.","JPN":"騎士団に戻る前に、少し散歩でもしないか？　新しい遊歩道を気に入ってもらえるといいのだが。","ENG":"Before you go back to the Knights, how'd you like to take a stroll with me? I'd love to show you our new promenade.","TWN":"回去騎士團之前要一起散個步嗎？有一條新的散步路線，希望你會喜歡。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"드나들 때마다 느끼지만, 보기보다 넓은 안뜰이군요.","JPN":"来るたびに思うのですが、意外と広い中庭ですね。","ENG":"Every time I come here, I can't help but admire this spacious courtyard you have.","TWN":"我每次來都覺得，這個地方比我看到的還寬敞呢。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"카운터 아카데미는 교직원들에 대한 대우에 상당히 공을 들이는 모양입니다.","JPN":"カウンターアカデミーは、教職員の待遇に相当力を入れているように感じます。","ENG":"The Counter Academy must be very good to its teaching staff.","TWN":"制裁者學院給教職員的待遇似乎非常大方呢。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"이 공간은 동료 중 한 명이 조금 손본 것이라네.","JPN":"この空間は、仲間の1人が少し手入れしたものだ。","ENG":"One of my colleagues worked her magic upon it.","TWN":"這個空間是有位同事稍微整修過的。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"순수한 선의만으로 만들지는 않았지만, 간혹 고민이 생기면 하염없이 걷기에 안성맞춤이지.","JPN":"ただの善意で作ったわけではないが、悩みがある時ただただ歩くにはもってこいの場所だよ。","ENG":"I doubt she created it purely out of the kindness of her heart, but still, I'm grateful to have a place to come to when I need to think.","TWN":"雖然不是出於善意而打造的空間，但偶爾遇到煩心的事時，很適合在這邊散心。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그 말씀은…….","JPN":"それは……","ENG":"You mean...","TWN":"教授的意思是……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"오늘은 평소보다 검이 무겁더군.","JPN":"今日は普段より剣に迷いがあった。","ENG":"Your sword was more sluggish than usual.","TWN":"你今天的動作比較沒那麼俐落喔。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"고민거리가 있다면 얘기해 보게.","JPN":"悩みがあるなら言いたまえ。","ENG":"You can talk to me if you have a problem.","TWN":"有什麼煩惱的話可以說出來。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"상담도 전술학의 일부란 사실은 처음 알았습니다.","JPN":"相談も戦術学の一部だとは知りませんでした。","ENG":"I didn't know consultation was part of strategy class.","TWN":"原來心理諮商也是戰術學的一部份嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"학생들의 고충을 상담해 주는 건 교사가 당연히 해야 할 일이라네.","JPN":"学生の悩みを聞くのは教師として当然のことだ。","ENG":"It's only natural that I want to help my students with their problems as their mentor.","TWN":"聆聽學生的煩惱是老師應該做的吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그리고 조디악 나이츠의 단장이라면, 없는 시간을 쪼개서라도 이야기를 나누고 싶군.","JPN":"しかもそれがゾディアックナイツの団長ともなると、暇を作ってでも話を聞いてみたいと思うものさ。","ENG":"Also, you're the captain of the Zodiac Knights. I can always make time for you.","TWN":"更何況你還是十二宮騎士團的團長，就算沒時間我也要擠出時間來聽你說。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그건…… 교수님의 집안이 조디악 나이츠를 오랜 세월 조력해 왔기 때문입니까?","JPN":"それは……教授の家が、長い間ゾディアックナイツに協力してきたからですか？","ENG":"Is it because... your family supported the Zodiac Knights for a long time?","TWN":"是因為……教授的家族一直以來都在協助十二宮騎士團嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};